import{_ as t,o as a,c as r,a4 as n}from"./chunks/framework.BybBnFXO.js";const p=JSON.parse('{"title":"Charge Transfer","description":"","frontmatter":{"title":"Charge Transfer","colorCause":"charge-transfer"},"headers":[],"relativePath":"color-causes/charge-transfer.md","filePath":"color-causes/charge-transfer.md","lastUpdated":1784176423000}'),o={name:"color-causes/charge-transfer.md"};function s(d,e,i,l,h,c){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="charge-transfer" tabindex="-1">Charge Transfer <a class="header-anchor" href="#charge-transfer" aria-label="Permalink to &quot;Charge Transfer&quot;">вҖӢ</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">вҖӢ</a></h2><p>Charge transfer involves an electron hopping between adjacent ions or between different energy states of the same ion, driven by absorbed photons. Compared to d-d transitions, charge- transfer absorption is typically 10ВІвҖ“10вҒҙ times stronger, so even trace concentrations of the relevant elements can produce saturated, vivid colors. Subtypes include metalвҖ“metal (MMCT), oxygenвҖ“metal (OMCT), and metalвҖ“ligand (MLCT).</p><h2 id="mechanism" tabindex="-1">Mechanism <a class="header-anchor" href="#mechanism" aria-label="Permalink to &quot;Mechanism&quot;">вҖӢ</a></h2><p><strong>MetalвҖ“metal CT (MMCT)</strong>: electron transfer between two adjacent metal ions. Classic example: FeВІвҒәвҖ“TiвҒҙвҒә in blue sapphire. Electron jumps from Fe to Ti, absorbing yellow-red light; transmitted light appears blue. <strong>OxygenвҖ“metal CT (OMCT)</strong>: OВІвҒ» вҶ’ metal ion (FeВівҒә, MnвҒҙвҒә, etc.). Often contributes alongside MMCT in blue and yellow sapphires. <strong>MetalвҖ“ligand CT (MLCT)</strong>: common in organic gem materials (e.g. pearl conchiolin).</p><h2 id="example-gemstones" tabindex="-1">Example Gemstones <a class="header-anchor" href="#example-gemstones" aria-label="Permalink to &quot;Example Gemstones&quot;">вҖӢ</a></h2><table tabindex="0"><thead><tr><th>Gem</th><th>Transfer Pair</th><th>Host</th><th>Color</th></tr></thead><tbody><tr><td>Blue Sapphire / и“қе®қзҹі</td><td>FeВІвҒәвҖ“TiвҒҙвҒә</td><td>AlвӮӮOвӮғ</td><td>blue</td></tr><tr><td>Amethyst / зҙ«жҷ¶</td><td>FeВІвҒә вҶ’ FeвҒҙвҒә (via OВІвҒ»)</td><td>SiOвӮӮ</td><td>violet</td></tr><tr><td>Yellow Sapphire / й»„е®қзҹі</td><td>FeВівҒәвҖ“OВІвҒ»</td><td>AlвӮӮOвӮғ</td><td>yellow</td></tr><tr><td>Aquamarine (deep) / жө·и“қе®қ</td><td>FeВІвҒәвҖ“FeВівҒә</td><td>BeвӮғAlвӮӮSiвӮҶOвӮҒвӮҲ</td><td>deep blue</td></tr><tr><td>Hematite / иөӨй“Ғзҹҝ</td><td>FeВІвҒәвҖ“FeВівҒә</td><td>FeвӮӮOвӮғ</td><td>red-brown</td></tr><tr><td>Kunzite / еӯ”иөӣзҹі</td><td>MnВІвҒә вҶ’ MnвҒҙвҒә</td><td>LiAlSiвӮӮOвӮҶ</td><td>pink (fades with light)</td></tr></tbody></table><p><em>See the <a href="./intro.html">color cause overview</a>.</em></p>',8)])])}const g=t(o,[["render",s]]);export{p as __pageData,g as default};
